from machine import ADC, Pin
import network, time
from umqtt.simple import MQTTClient

# Setup ESP32 to work with Wi-Fi and connect to your local WiFi router
sta_if = network.WLAN(network.STA_IF)
sta_if.active(True)
sta_if.connect('yourSSID', 'yourPASSWORD')  # Enter your SSID and password
while not sta_if.isconnected():
    time.sleep(1)
print('Connected to Wifi')

# Initialize ADC on ESP32 (temperature sensor in this case, replace with appropriate sensor if needed)
adc = ADC(Pin(34))  # Pin depends on your specific configuration

# Setup MQTT client. Replace 'broker_ip' with the IP address of your broker and enter the correct port if necessary (default is 1883).
client = MQTTClient("ESP32", "broker_ip") # MQTTBroker: use local Broker like "localhost" or add your IP addr as string 

# Connect to MQTT broker and subscribe to a topic. Replace 'sensors/temp' with the appropriate topic you want to publish to.
client.connect()
print("Connected to MQTT Broker")

while True:
    adc_val = adc.read()  # Read ADC value
    client.publish("sensors/temp", str(adc_val))   # Publish to "sensors/temp" topic on broker
    time.sleep(1)  # Delay between readings